"""
Spec2Prop-Edge: Generate Prediction Report
===========================================
Formats inference results into JSON, CSV, and Markdown reports.
"""

import json
import os
from datetime import datetime

import pandas as pd


DISCLAIMER = (
    "This is a screening-level prediction generated by the Spec2Prop-Edge "
    "inference pipeline. It is NOT experimental confirmation and should not "
    "be used as a substitute for laboratory analysis. Model performance is "
    "limited by training data coverage and instrument variability."
)


def generate_report(
    predictions: dict,
    output_dir: str = "deploy/outputs",
    prefix: str = "prediction_report",
) -> dict:
    """
    Generate JSON, CSV, and Markdown reports from a prediction dictionary.

    Parameters
    ----------
    predictions : dict
        Must contain keys like 'sample_id', 'task', 'model_name',
        'top_predictions', 'inference_time_ms', 'device', etc.
    output_dir : str
        Where to write the reports.
    prefix : str
        Filename prefix.

    Returns
    -------
    paths : dict
        Dictionary of output file paths.
    """
    os.makedirs(output_dir, exist_ok=True)

    # Add metadata
    predictions["timestamp"] = datetime.now().isoformat()
    predictions["disclaimer"] = DISCLAIMER

    paths = {}

    # JSON
    json_path = os.path.join(output_dir, f"{prefix}.json")
    with open(json_path, "w") as f:
        json.dump(predictions, f, indent=2, default=str)
    paths["json"] = json_path

    # CSV (flattened top predictions)
    csv_rows = []
    top_preds = predictions.get("top_predictions", [])
    for p in top_preds:
        row = {
            "sample_id": predictions.get("sample_id", "unknown"),
            "task": predictions.get("task", ""),
            "model": predictions.get("model_name", ""),
            "rank": p.get("rank", 0),
            "class": p.get("class", ""),
            "confidence": p.get("confidence", 0.0),
            "inference_time_ms": predictions.get("inference_time_ms", 0),
            "device": predictions.get("device", ""),
        }
        csv_rows.append(row)

    if csv_rows:
        csv_path = os.path.join(output_dir, f"{prefix}.csv")
        pd.DataFrame(csv_rows).to_csv(csv_path, index=False)
        paths["csv"] = csv_path

    # Markdown
    md_lines = [
        f"# Spec2Prop-Edge Prediction Report",
        f"",
        f"**Sample**: {predictions.get('sample_id', 'unknown')}",
        f"**Task**: {predictions.get('task', '')}",
        f"**Model**: {predictions.get('model_name', '')}",
        f"**Device**: {predictions.get('device', '')}",
        f"**Inference Time**: {predictions.get('inference_time_ms', 0):.2f} ms",
        f"**Timestamp**: {predictions.get('timestamp', '')}",
        f"",
        f"## Predictions",
        f"",
        f"| Rank | Class | Confidence |",
        f"|------|-------|------------|",
    ]
    for p in top_preds:
        md_lines.append(f"| {p.get('rank', '')} | {p.get('class', '')} | {p.get('confidence', 0):.4f} |")

    # Task-specific fields
    for field in ["predicted_family", "predicted_band_gap_class",
                   "predicted_is_metal", "predicted_formation_energy_class"]:
        if field in predictions:
            md_lines.append(f"\n**{field.replace('_', ' ').title()}**: {predictions[field]}")

    if predictions.get("warnings"):
        md_lines.append(f"\n## Warnings")
        for w in predictions["warnings"]:
            md_lines.append(f"- {w}")

    md_lines.append(f"\n---")
    md_lines.append(f"> {DISCLAIMER}")

    md_path = os.path.join(output_dir, f"{prefix}.md")
    with open(md_path, "w") as f:
        f.write("\n".join(md_lines))
    paths["md"] = md_path

    print(f"Reports saved: {', '.join(paths.values())}")
    return paths
